<?php
require_once __DIR__.'/../includes/kids-header.php';require_learner();$courses=kids_courses($pdo);
$s=$pdo->prepare('SELECT b.*,lb.awarded_at FROM learner_badges lb JOIN badges b ON b.id=lb.badge_id WHERE lb.learner_id=? ORDER BY lb.awarded_at DESC');$s->execute([learner_id()]);$badges=$s->fetchAll();
?>
<section class="progress-page"><div class="kids-container"><div class="progress-welcome"><div><span class="kids-kicker">Your learning stars</span><h1>Hi, <?=e($_SESSION['learner_name']??'Explorer')?>! 👋</h1><p>Every small step makes your tech superpowers stronger.</p></div><span class="star-count">⭐ <?=count($badges)?> badges</span></div><div class="progress-layout"><div><h2>My courses</h2><div class="progress-courses"><?php foreach($courses as $course):$p=kids_progress($pdo,learner_id(),(int)$course['id']);?><a href="<?=kids_url('course.php?slug='.urlencode($course['slug']))?>" style="--card-color:<?=e($course['theme_color'])?>"><span><?=e($course['icon'])?></span><div><h3><?=e($course['title'])?></h3><div class="big-progress"><i style="width:<?=$p['percent']?>%"></i></div><small><?=$p['done']?> of <?=$p['total']?> lessons • <?=$p['percent']?>%</small></div><b>→</b></a><?php endforeach?></div></div><aside class="badge-shelf"><h2>Badge shelf</h2><?php if(!$badges):?><div class="empty-badges">✨<p>Your first badge is waiting in the “What is AI?” adventure.</p></div><?php else:?><div class="badges-grid"><?php foreach($badges as $badge):?><div style="--badge-color:<?=e($badge['color'])?>"><span><?=e($badge['icon'])?></span><b><?=e($badge['name'])?></b><small><?=e(date('M j',strtotime($badge['awarded_at'])))?></small></div><?php endforeach?></div><?php endif?></aside></div></div></section>
